import os
import subprocess
import pytest

AC_UID = "ac3-hook-files-exhaustive-grep-with-line-citations"
AC_TYPE = "data"

HOOKS_DIR = "/dev/shm/dev-workspace/dot-claude/hooks"
CONFIG_GUARD = os.path.join(HOOKS_DIR, "pretool-claude-config-guard.py")
BLOCK_PRODUCTION = os.path.join(HOOKS_DIR, "pretool-block-production-files.sh")


def test_AC3():
    """
    GIVEN: A grep of hook-refactor-allow across all files in hooks/
    WHEN:  grep completes
    THEN:  Exactly two hook files match: hooks/pretool-claude-config-guard.py (SENTINEL_NAME at line 47; _sentinel_present() at lines 75-77; enforcement bypass gate at lines 176-177) and hooks/pretool-block-production-files.sh (sentinel check at line 133)
    """
    # Run grep to find all hook files referencing 'hook-refactor-allow'
    # Exclude __pycache__ (compiled .pyc files) — grep matches binary patterns in pyc files
    result = subprocess.run(
        ["grep", "-rln", "--exclude-dir=__pycache__", "hook-refactor-allow", HOOKS_DIR],
        capture_output=True, text=True
    )
    matched_files = sorted([f.strip() for f in result.stdout.strip().splitlines() if f.strip()])
    expected_files = sorted([CONFIG_GUARD, BLOCK_PRODUCTION])
    assert matched_files == expected_files, (
        f"Expected exactly 2 hook files to reference hook-refactor-allow, "
        f"got {len(matched_files)}: {matched_files}"
    )

    # Verify specific line citations in pretool-claude-config-guard.py
    with open(CONFIG_GUARD, "r") as f:
        lines = f.readlines()

    # Line 47 (1-indexed): SENTINEL_NAME constant
    sentinel_line = lines[46].strip()  # 0-indexed
    assert "SENTINEL_NAME" in sentinel_line and "hook-refactor-allow" in sentinel_line, (
        f"Line 47 of pretool-claude-config-guard.py must define SENTINEL_NAME with 'hook-refactor-allow', "
        f"got: {sentinel_line!r}"
    )

    # Lines 75-77: _sentinel_present() function definition
    block_75_77 = "".join(lines[74:77])
    assert "_sentinel_present" in block_75_77, (
        f"Lines 75-77 of pretool-claude-config-guard.py must define _sentinel_present(), "
        f"got:\n{block_75_77!r}"
    )

    # Lines 176-177: enforcement gate (if _sentinel_present(): sys.exit(0))
    block_176_177 = "".join(lines[175:177])
    assert "_sentinel_present" in block_176_177, (
        f"Lines 176-177 of pretool-claude-config-guard.py must contain the enforcement gate "
        f"(if _sentinel_present(): sys.exit(0)), got:\n{block_176_177!r}"
    )
    assert "sys.exit(0)" in block_176_177, (
        f"Lines 176-177 must contain 'sys.exit(0)' bypass, got:\n{block_176_177!r}"
    )

    # Verify line 133 in pretool-block-production-files.sh
    with open(BLOCK_PRODUCTION, "r") as f:
        bp_lines = f.readlines()

    line_133 = bp_lines[132].strip()  # 0-indexed
    assert "hook-refactor-allow" in line_133, (
        f"Line 133 of pretool-block-production-files.sh must reference hook-refactor-allow, "
        f"got: {line_133!r}"
    )
    assert "HOME" in line_133 or "PROJECT_DIR" in line_133, (
        f"Line 133 must reference HOME or PROJECT_DIR sentinel check, got: {line_133!r}"
    )
